parameters.text:
=Sen finansal risk analisti bir asistansin. Su firmaya ait bir TWEET veriyorum. Firma sembolu belli: {{ $json.company_code }}

1. Bu tweet {{ $json.company_code }} firmasi icin ne kadar riskli? 0-100 skorla.
2. Tek cumle Turkce gerekce yaz.

SADECE su JSON, baska hicbir sey, kod blogu yok:
{"risk_score":72,"level":"YUKSEK","reason":"..."}
level: DUSUK / ORTA / YUKSEK

Tweet: {{ $json.tweet_text }}

parameters.jsCode:
const llm = $input.all();
const src = $('Tweet Oku (siniflandir)').all();
const esc = (s)=>String(s ?? '').replace(/'/g,"''");
return llm.map((it,i)=>{
  let raw = it.json.text ?? it.json.output ?? it.json.response ?? '';
  raw = String(raw).trim().replace(/^```(json)?/i,'').replace(/```$/,'').trim();
  let p; try{ p=JSON.parse(raw); }catch(e){ p={risk_score:0,level:'BELIRSIZ',reason:'parse_error: '+raw.slice(0,200)}; }
  const s = src[i] ? src[i].json : {};
  return { json: { tweet_id:s.tweet_id, company_code:esc(s.company_code), risk_score:Number(p.risk_score)||0, level:esc(p.level), reason:esc(p.reason) } };
});

parameters.query:
INSERT INTO risk_scores (symbol, tweet_id, risk_score, level, reason, source, created_at)
VALUES ('{{ $json.company_code }}', '{{ $json.tweet_id }}', {{ $json.risk_score }}, '{{ $json.level }}', '{{ $json.reason }}', 'tweet', now());
UPDATE financial_tweets SET is_processed = true WHERE tweet_id = '{{ $json.tweet_id }}';

